var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"러처가 이 타이밍에 나타날 줄은 몰랐네요.","JPN":"ラッチャーがこのタイミングで現われるなんて。","ENG":"Didn't think Lurcher would barge in at this timing.","TWN":"沒想到獵犬會在這個時候出現。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"오히려 잘 됐어요. 제가 녀석을 도망치지 못하게 붙잡으면 확실히 처리할 수 있을 테니까.","JPN":"むしろ好都合です。私がやつを逃げさなければ、確実に処理できるはずですから。","ENG":"Maybe it's for the better. If I stop it from running away, I'll be able to finish it for sure.","TWN":"來得正好。只要它不逃跑，我一定能在這裡結束它。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"제가 받은 명령은 셰퍼드를 제외한 연구 자료를 남김없이 제거하는 거거든요.","JPN":"私に下された命令は、シェパードを除く全ての研究資料を消去することなんです。","ENG":"My orders were to discard every shred of research in this facility except for Shepherd.","TWN":"畢竟收到的命令是銷毀除牧羊犬之外的所有研究素材嘛。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"여유롭네.","JPN":"余裕そうだな。","ENG":"You're in no hurry at all.","TWN":"真有自信啊。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇게 말하는 넌… 폭발에서 살아남을 자신이 있는 건가?","JPN":"そういうあなたは……爆発から生き残る自信はあるのか？","ENG":"Are you confident that you'll survive the explosion?","TWN":"說出這種話的你……有信心從爆炸中活下來嗎？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"에이, 아무리 저라도 멜트다운 급의 폭발에서 살아남긴 힘들지 않을까요?","JPN":"さすがに私でも、メルトダウン級の爆発だったら生き残れないと思いますよ。","ENG":"C'mon, I don't think even I can survive a meltdown-level explosion, don't you think?","TWN":"哎呀，就算是我，也很難在這種火山噴發級的爆炸中活下來吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"하지만, 딱히 상관없어요.","JPN":"でも、別に関係ないです。","ENG":"Nevertheless, it doesn't matter.","TWN":"但是，這並不重要啊？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"상냥한 오라버니가 지옥에서 동생을 애타게 부르고 있을 테니까요.","JPN":"優しいお兄さんが地獄から私を何度も呼んでますから。","ENG":"My sweet brother will be calling out my name from hell.","TWN":"因為我那善良的哥哥一定在地獄裡拼命呼喚著他的妹妹呢！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"너…! 그렇게 하면서까지 네가 대체 얻는 게 뭔데…!","JPN":"あなた……！　そこまでして、あなたはいったい何を手に入れようと……！","ENG":"You...! What do you even gain from all of this...?","TWN":"你……！這樣做你到底能得到什麼？！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"크윽…?!","JPN":"うっ……！？","ENG":"Krrgh...?!","TWN":"呃……？！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"말 좀 아끼라니까요.","JPN":"もう話さないでって言ったじゃないですか。","ENG":"See? I told you to stop talking.","TWN":"我告訴你要少說話了吧。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"피가 자꾸 흐르잖아요.","JPN":"出血がもっとひどくなりますよ。","ENG":"You're gonna lose even more blood.","TWN":"你的血一直流個不停。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"안돼…!","JPN":"ダメ……！","ENG":"No...!","TWN":"不要……！"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"걱정 마. 지혈하면서 잠깐 기절한 거니까.","JPN":"心配しないでください。止血する途中で少し気絶しただけですから。","ENG":"Don't worry. She just fainted from the pressure on her wound.","TWN":"不用擔心。她只是在止血的時候暈過去了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"나 이래 봬도 아이가 보는 앞에서 누굴 죽이진 않아.","JPN":"私もさすがに子どもの前では誰かを殺したりはしませんよ。","ENG":"I may look cruel, but I don't kill people in front of children.","TWN":"別看我這樣，我也不會在孩子面前殺人的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"게다가…","JPN":"それに……","ENG":"Besides...","TWN":"而且……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"내가 전력으로 싸우면 좀 추해져서. 이 사람에겐 보여주기 싫거든.","JPN":"私が本気で戦ったら、ちょっとブサイクになっちゃいますから。この人にはそんな姿を見せたくないんです。","ENG":"If I fight with everything I've got, I look ugly. And I don't want to show her that.","TWN":"如果我全力戰鬥的話，會有些不太好看。我可不想讓她看到。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DINO_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_MINI_MOVE_ATTACK"},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신의 마음은… 흐릿하고 모양이 없어요.","JPN":"あなたの心は……ぼんやりして、形がないね。","ENG":"Your heart... it's blurry and has no shape.","TWN":"你的心……很模糊。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"둥글지도 않고, 뾰족하지도 않아.","JPN":"丸くもないし、トゲトゲでもない。","ENG":"It's not round or pointy.","TWN":"它既不是圓的，也不是尖的。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"우릴 미워하지 않으면서, 미워하는 것처럼 괴롭혀요.","JPN":"シェパードたちを恨んでないのに、恨んでるようにいじめる。","ENG":"You don't hate us, but you treat us as if you do.","TWN":"你不恨我們，卻像恨著我們一樣欺負我們。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"몸이 아파도, 항상 웃고 있어요.","JPN":"体が痛くても、いつも笑ってる。","ENG":"Even when your body hurts, you keep on smiling.","TWN":"即使身體很痛，也一直微笑著。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"당신의 마음을… 모르겠어요.","JPN":"あなたの心……わからないよ。","ENG":"Shepherd can't understand... your heart.","TWN":"我看不懂……你的心。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"응, 자주 듣는 얘기야.","JPN":"はい、よく言われます。","ENG":"Yeah, I get that a lot.","TWN":"好啦好啦，你的意思我懂。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"그치만 누가 날 이해해야 내가 더 행복해지는 건 아니잖아?","JPN":"でも、誰かが私のことを理解してくれたって、もっと幸せになれるわけじゃないでしょう？","ENG":"But it's not like I need someone to understand me to be happy, right?","TWN":"但我不需要別人理解我才能獲得快樂，對吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"아하하, 그렇게 보채지 않아도 돼. 나도 네가 주는 자극이 그리웠거든.","JPN":"あはは、そんなに急かさないでください。私もあなたからの刺激が懐かしかったんです。","ENG":"Ah ha ha, no need to be in a hurry like that. I've also missed the stimulation you gave me too.","TWN":"哈哈，你不用這麼大驚小怪的。我也很懷念你給我的刺激。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SAW_REAPER_NULL_NULL","text":{"KOREA":"우리, 마지막까지 피 터지게 싸워보자?","JPN":"私たち、最後まで全力で戦いましょう？","ENG":"So let's fight until one of us dies, okay?","TWN":"來，我們來戰鬥到最後吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"THEMA_CA_DINO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};